        validate({
            token: { type: 'string', required: false },
            needReconnect: { type: 'boolean', required: false },
            reconnectionAttempts: { type: 'number', required: false },
            customClientType: { type: 'number', min: 1, required: false },
            authType: { type: 'number', min: 0, max: 2, required: false },
            lbsUrls: { type: 'array', itemType: 'string', min: 1, required: false },
            linkUrl: { type: 'string', allowEmpty: false, required: false }
        }, options);
        this.logger.log('NIM::setOptions options is', options);
        this.options = {
            ...this.options,
            ...options
        };
        // 尝试把 options 的配置内容移动去 V1NIMLoginService 配置。因为 v2 来了, 参数不能都挂在初始化的第一个位置.
        this.V1NIMLoginService.setOptions && this.V1NIMLoginService.setOptions(this.options);
