// WebSocket 状态常量
const CONNECTING = 0;
const OPEN = 1;
const CLOSING = 2;
const CLOSED = 3;
/**
 * Node.js WebSocket 包装类，适配 AdapterWebSocket 接口
 */
class NodeWebSocket {
    constructor(url, protocols) {
        // 事件回调
        this.onopen = null;
        this.onclose = null;
        this.onerror = null;
        this.onmessage = null;
        // 二进制类型
        this.binaryType = 'arraybuffer';
        // 状态常量
        this.CONNECTING = CONNECTING;
        this.OPEN = OPEN;
        this.CLOSING = CLOSING;
        this.CLOSED = CLOSED;
        this.ws = new WebSocket(url, protocols);
        // 绑定事件
        this.ws.on('open', () => {
            if (this.onopen) {
                this.onopen.call(this, { type: 'open' });
            }
        });
        this.ws.on('close', (code, reason) => {
            if (this.onclose) {
                this.onclose.call(this, {
                    type: 'close',
                    code,
                    reason: reason.toString(),
                    wasClean: code === 1000
                });
            }
        });
        this.ws.on('error', (error) => {
            if (this.onerror) {
                this.onerror.call(this, {
                    type: 'error',
                    error,
                    message: error.message
                });
            }
        });
        this.ws.on('message', (data) => {
            if (this.onmessage) {
                let messageData;
                if (this.binaryType === 'arraybuffer') {
                    if (Buffer.isBuffer(data)) {
                        // 将 Buffer 转换为 ArrayBuffer
                        messageData = data.buffer.slice(data.byteOffset, data.byteOffset + data.byteLength);
                    }
                    else if (Array.isArray(data)) {
                        // Buffer 数组，合并为单个 ArrayBuffer
                        const buffer = Buffer.concat(data);
                        messageData = buffer.buffer.slice(buffer.byteOffset, buffer.byteOffset + buffer.byteLength);
                    }
                    else {
                        messageData = data;
                    }
                }
                else {
                    messageData = data.toString();
                }
                this.onmessage.call(this, {
                    type: 'message',
                    data: messageData
                });
            }
        });
    }
    /**
     * 获取当前连接状态
     */
    get readyState() {
        return this.ws.readyState;
    }
    /**
     * 发送数据
     */
    send(data) {
        if (data instanceof ArrayBuffer) {
            this.ws.send(Buffer.from(data));
        }
        else if (ArrayBuffer.isView(data)) {
            this.ws.send(Buffer.from(data.buffer, data.byteOffset, data.byteLength));
        }
        else if (typeof data === 'string') {
            this.ws.send(data);
        }
        else {
            data.arrayBuffer().then((buffer) => {
                this.ws.send(Buffer.from(buffer));
            });
        }
    }
    /**
     * 关闭连接
     */
    close(code, reason) {
        this.ws.close(code, reason);
    }
}
// 创建一个类似浏览器 WebSocket 的构造函数类型
const NodeWebSocketConstructor = NodeWebSocket;

/**
 * Node.js 内存存储实现，符合 AdapterStorage 接口
 * 注意：进程重启后数据会丢失
 */
class MemoryStorage {
    constructor() {
        this.storage = new Map();
    }
    /**
     * 获取存储项
     */
    getItem(key) {
        return this.storage.get(key) ?? null;
    }
    /**
     * 设置存储项
     */
    setItem(key, value) {
        this.storage.set(key, value);
    }
    /**
     * 移除存储项
     */
    removeItem(key) {
        this.storage.delete(key);
    }
    /**
     * 清空所有存储
     */
    clear() {
        this.storage.clear();
    }
}
// 导出单例实例
const localStorage = new MemoryStorage();

/**
 * Node.js HTTP 请求实现，基于原生 fetch API (Node.js 20+)
 */
async function requestFn(url, config) {
    const method = config?.method || 'GET';
    const timeout = config?.timeout || 30000;
    const headers = {
        'Content-Type': 'application/json',
        ...config?.headers
    };
    // 处理 URL 参数
    let finalUrl = url;
    if (config?.params && Object.keys(config.params).length > 0) {
        const searchParams = new URLSearchParams();
        for (const [key, value] of Object.entries(config.params)) {
            if (value !== undefined && value !== null) {
                searchParams.append(key, String(value));
            }
        }
        const queryString = searchParams.toString();
        if (queryString) {
            finalUrl += (url.includes('?') ? '&' : '?') + queryString;
        }
    }
    // 超时控制
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);
    try {
        const fetchOptions = {
            method,
            headers,
            signal: controller.signal
        };
        // 添加请求体 (非 GET 请求)
        if (config?.data && method !== 'GET') {
            fetchOptions.body = JSON.stringify(config.data);
        }
        const response = await fetch(finalUrl, fetchOptions);
        clearTimeout(timeoutId);
        // 解析响应
        let data;
        const contentType = response.headers.get('content-type') || '';
        if (contentType.includes('application/json')) {
            data = await response.json();
        }
        else {
            data = await response.text();
        }
        // 转换 headers 为普通对象
        const responseHeaders = {};
        response.headers.forEach((value, key) => {
            responseHeaders[key] = value;
        });
        const result = {
            data,
            headers: responseHeaders,
            status: response.status
        };
        // 检查状态码
        if (response.ok) {
            return result;
        }
        else {
            const dataObj = data;
            throw {
                code: response.status,
                message: dataObj?.message || data || `Request failed with status ${response.status}`,
                response: result
            };
        }
    }
    catch (error) {
        clearTimeout(timeoutId);
        const err = error;
        // 处理超时错误
        if (err.name === 'AbortError') {
            throw {
                code: 0,
                message: `Request timeout after ${timeout}ms. url: ${finalUrl}`
            };
        }
        // 处理网络错误
        if (err.code !== undefined) {
            throw error;
        }
        throw {
            code: 0,
            message: err.message || `Request failed. url: ${finalUrl}`
        };
    }
}

/**
 * Node.js 文件上传实现，使用 fs 读取文件 + FormData 表单上传
 */
async function uploadFileFn(options) {
    // Node.js 环境支持两种方式获取文件路径:
    // 1. options.filePath - 直接传递文件路径
    // 2. options.file.path - 通过 file 对象传递文件路径 (类似浏览器 File API 但带有 path)
    const filePath = options.filePath || (options.file && typeof options.file === 'object' && 'path' in options.file ? options.file.path : undefined);
    if (!filePath) {
        throw new Error('filePath or file.path is required for Node.js file upload');
    }
    // 检查文件是否存在
    if (!fs.existsSync(filePath)) {
        throw new Error(`File not found: ${filePath}`);
    }
    // 读取文件信息
    const stats = fs.statSync(filePath);
    const fileSize = stats.size;
    const fileName = path.basename(filePath);
    const fileExt = path.extname(filePath).slice(1).toLowerCase();
    // 大小限制检查
    if (options.maxSize && fileSize > options.maxSize) {
        throw new Error(`The file exceeds maxSize limit. maxSize: ${options.maxSize}, get ${fileSize}`);
    }
    // 创建 AbortController 用于取消上传
    const controller = new AbortController();
    const task = {
        abort: () => controller.abort()
    };
    // 触发上传开始回调
    if (options.onUploadStart) {
        options.onUploadStart(task);
    }
    // 读取文件内容
    const fileContent = fs.readFileSync(filePath);
    const blob = new Blob([fileContent]);
    // 构建 FormData
    const formData = new FormData();
    // NOS 要求 objectName 进行 URL 解码
    formData.append('Object', decodeURIComponent(options.nosToken.objectName));
    formData.append('x-nos-token', options.nosToken.token);
    // 告诉 NOS 以 JSON 格式返回响应
    formData.append('x-nos-entity-type', 'json');
    if (options.md5) {
        formData.append('Content-MD5', options.md5);
    }
    formData.append('file', blob, fileName);
    // 上传文件 - 非浏览器环境需要带上 bucket 路径
    // 格式: {commonUploadHost}/{bucket}
    const baseUrl = options.commonUploadHost || options.chunkUploadHost;
    const uploadUrl = options.nosToken.bucket ? `${baseUrl}/${options.nosToken.bucket}` : baseUrl;
    try {
        const response = await fetch(uploadUrl, {
            method: 'POST',
            body: formData,
            signal: controller.signal,
            headers: options.headers
        });
        if (!response.ok) {
            const errorText = await response.text();
            throw new Error(`Upload failed with status ${response.status}: ${errorText}`);
        }
        // 触发上传进度回调 (上传完成)
        if (options.onUploadProgress) {
            options.onUploadProgress({
                total: fileSize,
                loaded: fileSize,
                percentage: 1,
                percentageText: '100%'
            });
        }
        // 构建返回结果
        const result = {
            name: fileName,
            ext: fileExt,
            size: fileSize,
            type: options.type || 'file',
            bucketName: options.nosToken.bucket,
            objectName: options.nosToken.objectName,
            token: options.nosToken.token,
            ctx: ''
        };
        return result;
    }
    catch (error) {
        const err = error;
        if (err.name === 'AbortError') {
            throw new Error('Upload aborted');
        }
        throw error;
    }
}
