function formatTeamFromTinfo(tinfo) {
    return deserialize(tinfo, invertSerializeItem(teamTag));
}
// export function formatSuperTeamsFromTeam(teams: V2NIMTeam[]): V2NIMTeam[] {
//   return teams.map((team) => {
//     team.teamType = V2NIMTeamType.V2NIM_TEAM_TYPE_SUPER
//     return team
//   })
// }
function formatTeamNotificationAttachData(attachDataRaw, teamType) {
    if (!attachDataRaw)
        return {};
    const resultData = attachDataRaw;
    if (resultData.tinfo) {
        resultData.tinfo = formatTeamFromTinfo(resultData.tinfo);
        resultData.tinfo.teamType = teamType;
    }
    if (resultData.uinfos) ;
    if (typeof resultData.mute !== 'undefined') {
        resultData.mute = parseInt(resultData.mute);
    }
    return resultData;
}

/**
 * 消息二次加工处理函数.
 *
 * 1. 补充无法从协议中直接得到的消息字段。
 * 2. 解析 attachment 附件.
 */
function completeMessage(core, message, messageSource) {
    const retMsg = {
        ...message,
        conversationId: core.V2NIMConversationIdUtil.messageConversationId(message),
        isSelf: message.senderId === core.account,
        /**
         * completeMessage使用场景：
         * 1. v1 & v2 message 相互转换场景
         * 2. 拉取服务器消息, getMessageList, getMessageByRefers
         * 3. 同步、在线下行消息
         *
         * 场景1会在调用 completeMessage 后，覆盖 sendingState
         * 场景2、3的 sendingState 就应该是 succeed，因为这些消息都是已经发送成功的消息
         *
         * 另外注意，v1被拉黑发送的消息会在下行时接收到，所以这里其实逻辑上是存在漏洞的。但是这个场景太罕见了，这里不处理（和胖总商量过）
         */
        sendingState: 1 /* V2NIM_MESSAGE_SENDING_STATE_SUCCEEDED */,
        // feat: OMIM-54450 消息新增发送失败状态错误码. 默认 200
        messageStatus: {
            errorCode: message?.messageStatus?.errorCode || 200
        },
        // 添加消息来源
        messageSource: messageSource || 0 /* V2NIM_MESSAGE_SOURCE_UNKNOWN */
    };
    /**
     * 从服务器返回的消息 threadReply/threadRoot 中，缺少 conversationType，以及 conversationId
     */
    if (retMsg.threadReply) {
        retMsg.threadReply = {
            ...retMsg.threadReply,
            conversationType: retMsg.conversationType,
            conversationId: retMsg.conversationId
        };
    }
    if (retMsg.threadRoot) {
        retMsg.threadRoot = {
            ...retMsg.threadRoot,
            conversationType: retMsg.conversationType,
            conversationId: retMsg.conversationId
        };
    }
    // 如果被拉黑，则修改发送状态为失败，并设置错误码为 V2NIMErrorCode.V2NIM_ERROR_CODE_ACCOUNT_IN_BLOCK_LIST
    if (retMsg.isInBlackList) {
        retMsg.sendingState = 2 /* V2NIM_MESSAGE_SENDING_STATE_FAILED */;
        retMsg.messageStatus.errorCode = V2NIMErrorCode.V2NIM_ERROR_CODE_ACCOUNT_IN_BLOCK_LIST;
        delete retMsg.isInBlackList;
    }
    // 咨询国勇, 当 65号(映射为 message.streamConfig.isStream) 为 true 且存在 67号(message.streamConfig.status) 时就为一个流式消息.
    if (retMsg.streamConfig) {
        const isStream = get(retMsg.streamConfig, 'isStream');
        if (isStream === false) {
            // 防御代码, 防一手 isStream 为 false, 服务器特意返回了这个字段为 false 的情况
            delete retMsg.streamConfig;
        }
        else if (isStream === true && typeof retMsg.streamConfig.status === 'undefined') {
            // 65 存在未 true 而 67 不存在的情况: 账号 A 向 AI 提问一条消息, 账号 A getMessageList 查询到这条提问消息.
            // 强行给他赋值上 ai 相关字段.
            delete retMsg.streamConfig;
            if (message.aiConfig) {
                message.aiConfig.aiStream = true;
                message.aiConfig.aiStreamStatus = 0 /* NIM_MESSAGE_AI_STREAM_STATUS_NONE */;
            }
        }
        else if (typeof retMsg.streamConfig.status === 'number') {
            // streamConfig.isStream 为 true 且 status 流式状态存在
            // 情况: 这就是一条正在流式中, 或者流式完成的响应消息
            retMsg.streamConfig = {
                status: retMsg.streamConfig.status
            };
            return completeMessageStreamConfig(retMsg);
        }
    }
    // ai 消息一定需要有一个 aiAccount, 否则没有存在的意义.
    if (retMsg.aiConfig && typeof retMsg.aiConfig.accountId === 'undefined') {
        delete retMsg.aiConfig;
    }
    // v10.9.1 优化一下, 让 completeMessage 作为消息二次加工函数, 直接包括 formatMessageAttachment 的调用.
    // 省掉上层还得调用 一次 formatMessageAttachment, 增加消息处理的心智负担
    return formatMessageAttachment(retMsg, core);
}
