class NotificationUtil {
    constructor(core) {
        this.core = core;
    }
    generateNotificationTag(conversationId, content, params = {}) {
        const conversationType = this.core.V2NIMConversationIdUtil.parseConversationType(conversationId);
        const receiverId = this.core.V2NIMConversationIdUtil.parseConversationTargetId(conversationId);
        const now = Date.now();
        /**
         * 将自定义消息类型转换为 systemMessageType 中的类型
         */
        const typeMap = {
            [1 /* V2NIM_CONVERSATION_TYPE_P2P */]: 100,
            [2 /* V2NIM_CONVERSATION_TYPE_TEAM */]: 101,
            [3 /* V2NIM_CONVERSATION_TYPE_SUPER_TEAM */]: 103
        };
        return {
            ...params,
            notificationConfig: {
                unreadEnabled: true,
                offlineEnabled: true,
                ...params?.notificationConfig
            },
            pushConfig: {
                pushEnabled: true,
                pushNickEnabled: true,
                ...params?.pushConfig
            },
            antispamConfig: {
                antispamEnabled: true,
                ...params?.antispamConfig
            },
            routeConfig: {
                routeEnabled: true,
                ...params?.routeConfig
            },
            timestamp: now,
            type: typeMap[conversationType],
            receiverId,
            content
        };
    }
}

function getFileOrPath(fileObj) {
    let file = typeof fileObj === 'object' ? fileObj : undefined;
    const path = typeof fileObj === 'string' ? fileObj : undefined;
    if (!file && !path) {
        throw new V2NIMErrorImpl({
            code: V2NIMErrorCode.V2NIM_ERROR_CODE_MISUSE,
            detail: { reason: 'getFileOrPath::incorrect file and path' }
        });
    }
    // 后门, 匹配 nim-external 开头的字符串做 fileInput.
    // 为了便于 api 测试，所以设置一个 fileInput 参数，但是不对外开放
    if (typeof path === 'string') {
        if (path.indexOf('nim-external') === 0) {
            const dom = document.getElementById(path);
            if (dom && dom.files && dom.files[0]) {
                file = dom.files[0];
                // path = undefined
            }
            else {
                throw new V2NIMErrorImpl({
                    code: V2NIMErrorCode.V2NIM_ERROR_CODE_FILE_NOT_FOUND,
                    detail: { reason: `getFileOrPath::file not exist: ${path}` }
                });
            }
        }
        else if (Adapters.platform === 'BROWSER') {
            // 浏览器平台下传的是字符串，但又不是后门 nim-external 打头的字符串，使用姿势错误
            throw new V2NIMErrorImpl({
                code: V2NIMErrorCode.V2NIM_ERROR_CODE_MISUSE,
                detail: { reason: `getFileOrPath::incorrect path: ${path}` }
            });
        }
    }
    if (typeof file === 'object' && typeof file.size === 'undefined') {
        throw new V2NIMErrorImpl({
            code: V2NIMErrorCode.V2NIM_ERROR_CODE_MISUSE,
            detail: { reason: `getFileOrPath::file no size` }
        });
    }
    return { file, path };
}

