        this.core.eventBus.on('forwardReceive/V2NIMMessageService/revokeMessages', this.service.deleteUtil.emitRevokeMessage.bind(this.service.deleteUtil));
        this.core.eventBus.on('forwardReceive/V2NIMMessageService/deleteMessages', this.service.deleteUtil.deleteMessagesFn.bind(this.service.deleteUtil));
