// setListener 事件处理器
class V2NIMAIEventImpl {
    constructor(core, service) {
        this.core = core;
        this.service = service;
        this.logger = this.core.logger;
    }
    setListener() {
        // ...
    }
    beforeEmit(event, ...args) {
        const prefix = `${this.service.name}::emit ${event.toString()}`;
        if (event === 'onProxyAIModelCall') {
            const data = args[0];
            this.logger.log(`${prefix}`, `requestId:${data.requestId};aiStreamStatus:${data.aiStreamStatus}`);
        }
        else if (event === 'onProxyAIModelStreamCall') {
            const data = args[0];
            this.logger.log(`${prefix}`, `requestId:${data.requestId};chunkIndex:${data.content?.lastChunk.index};chunkTime:${data.content?.lastChunk.chunkTime}`);
        }
        else {
            this.logger.log(`${prefix}`, ...args);
        }
    }
}

