        // 数据订正: 遵照 owner 金涛的意思, 只要在流式过程中, aiStreamStatus 直接被设置为 -1.
        msg.streamConfig.status = -1;
        if (msg.aiConfig)
            msg.aiConfig.aiStreamStatus = -1;
