        msg.text = streamCache.chunks.join('');
        // 数据订正: 缓存里若有 aiRAGs 则附带上去
        if (streamCache.aiRAGs && msg.aiConfig) {
            msg.aiConfig.aiRAGs = streamCache.aiRAGs;
        }
